  "tensor_make_range.h":
    "/* mtoc2 runtime helper: build a freshly-owned 1×N row tensor for a\n * `start : step : end` range used as a value (outside an index slot\n * and outside a for-loop iterable).\n *\n * The count is computed via `mtoc2_loop_count`; the result tensor is\n * allocated via `mtoc2_tensor_alloc_nd` so it lives in the standard\n * owned-tensor lifecycle (assign / copy / free). Caller is expected\n * to consume the result via `mtoc2_tensor_assign(&v, ...)` (or as a\n * fresh function-call arg).\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_make_range(double start, double step, double end) {\n  long n = mtoc2_loop_count(start, end, step);\n  mtoc2_tensor_t t = mtoc2_tensor_alloc_nd(2, (long[]){1, n});\n  for (long k = 0; k < n; k++) {\n    t.real[k] = mtoc2_range_value(start, step, end, n, k);\n  }\n  return t;\n}\n",
  "assert_fail.h":
    "/* mtoc2 runtime helper: scalar `assert(cond, msg)`. Tests `cond` for\n * MATLAB truthiness (non-zero and not NaN); fires `abort()` after\n * printing the message to stderr if the test fails.\n *\n * Numbl's `assert` (`interpreter/builtins/utility.ts:151`) accepts\n * tensor conds too — every element must be non-zero and not NaN. We\n * only support scalar conds in v1 (chunkie_simple's `assert(n >= 0,\n * ...)` is scalar-comparison-result anyway). Tensor-cond support is\n * a small followup.\n *\n * `msg` may be NULL or empty; the printer falls back to a generic\n * \"assertion failed\" line in that case.\n */\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic void mtoc2_assert_scalar(double cond, const char *msg) {\n  /* `cond != cond` filters NaN — numbl's `isNaN(v)` check. */\n  if (cond != 0.0 && cond == cond) return;\n  fputs(\"mtoc2: assertion failed\", stderr);\n  if (msg != NULL && msg[0] != '\\0') {\n    fputs(\": \", stderr);\n    fputs(msg, stderr);\n  }\n  fputc('\\n', stderr);\n  abort();\n}\n",
  "assert_fmt.h":
    '/* mtoc2 runtime helper: `assert(cond, fmt, args...)` — printf-style\n * assertion failure.\n *\n * Tests `cond` for MATLAB truthiness (non-zero and not NaN); on\n * failure, writes "mtoc2: assertion failed: " followed by the\n * formatted body to stderr and aborts. Uses the shared format engine\n * (`mtoc2__format_walk`), so the spec set / escape rules / arg\n * cycling match `fprintf` / `error`.\n *\n * Routed to by the lowerer whenever `assert(cond, ...)` has 2+ args\n * AND the message is either an opaque text variable or carries\n * additional format args. The simpler 2-arg literal-message form\n * stays on `mtoc2_assert_scalar` (no engine activation needed).\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic void mtoc2__assert_fmt_writer(void *ctx, const char *bytes, long len) {\n  (void)ctx;\n  if (len > 0) fwrite(bytes, 1, (size_t)len, stderr);\n}\n\nstatic void mtoc2_assert_scalar_fmt(double cond, mtoc2_text_view_t fmt,\n                                    int nargs,\n                                    const mtoc2_fprintf_arg_t *args) {\n  if (cond != 0.0 && cond == cond) return;\n  fputs("mtoc2: assertion failed: ", stderr);\n  mtoc2__format_walk(mtoc2__assert_fmt_writer, (void *)0, fmt, nargs, args);\n  fputc(\'\\n\', stderr);\n  abort();\n}\n',
  "disp_complex.h":
    '/* mtoc2 runtime helper: disp(z) for a scalar `double _Complex`.\n *\n * Mirrors numbl\'s `formatComplex` (via mtoc2_format_complex) so\n * cross-runner test output matches byte-for-byte. The actual\n * formatting lives in `format_complex.h`; this snippet only wraps\n * it with a print + newline.\n */\n\n#include <complex.h>\n#include <stdio.h>\n\nstatic void mtoc2_disp_complex(double _Complex z) {\n  char buf[160];\n  mtoc2_format_complex(buf, sizeof(buf), z);\n  mtoc2_stdout_s(buf);\n  mtoc2_stdout("\\n", 1);\n}\n',
